// Calcula el rango de la semana anterior (lunes 00:00 a domingo 23:59)
// y arma el cuerpo de la consulta structuredQuery para Firestore REST API.

const now = new Date();
// Retrocede 7 días para cubrir la semana que acaba de terminar
const end = new Date(now);
end.setDate(end.getDate() - ( (now.getDay() + 6) % 7 )); // lunes de esta semana
end.setHours(0, 0, 0, 0);
const start = new Date(end);
start.setDate(start.getDate() - 7); // lunes anterior

const startISO = start.toISOString();
const endISO = end.toISOString();

// Consulta: trae los trabajos/servicios de la semana anterior.
// Ajusta 'collectionId' y los nombres de campo a tu esquema real de Firestore.
const query = {
  structuredQuery: {
    from: [{ collectionId: 'solicitudes' }],
    where: {
      compositeFilter: {
        op: 'AND',
        filters: [
          {
            fieldFilter: {
              field: { fieldPath: 'fechaCreacion' },
              op: 'GREATER_THAN_OR_EQUAL',
              value: { timestampValue: startISO }
            }
          },
          {
            fieldFilter: {
              field: { fieldPath: 'fechaCreacion' },
              op: 'LESS_THAN',
              value: { timestampValue: endISO }
            }
          }
        ]
      }
    }
  }
};

return [{
  json: {
    query,
    semana: {
      inicio: startISO,
      fin: endISO,
      etiqueta: `${start.toLocaleDateString('es-EC')} — ${new Date(end.getTime()-1).toLocaleDateString('es-EC')}`
    }
  }
}];

// Agrupa los documentos de Firestore por proveedor y calcula las métricas
// de la semana: solicitudes recibidas, cotizaciones enviadas, trabajos
// ganados, calificación promedio y ganancias.
//
// La respuesta de runQuery llega como un item por documento, cada uno con
// { document: { fields: {...} } } en formato Firestore. Aquí lo aplanamos.

const semana = $('Preparar Consulta').first().json.semana;

// Helper: convierte un valor de campo Firestore a valor JS plano
function fv(field) {
  if (field == null) return null;
  if ('stringValue' in field) return field.stringValue;
  if ('integerValue' in field) return Number(field.integerValue);
  if ('doubleValue' in field) return Number(field.doubleValue);
  if ('booleanValue' in field) return field.booleanValue;
  if ('timestampValue' in field) return field.timestampValue;
  return null;
}

// Acumulador por proveedor
const acc = {};

for (const item of $input.all()) {
  const doc = item.json.document;
  if (!doc || !doc.fields) continue; // filas 'readTime' sin documento
  const f = doc.fields;

  const provId    = fv(f.proveedorId);
  if (!provId) continue;

  const provNombre = fv(f.proveedorNombre) || 'Proveedor';
  const provEmail  = fv(f.proveedorEmail);
  const estado     = fv(f.estado);            // ej: 'cotizada', 'ganada', 'completada'
  const cotizo     = fv(f.cotizacionEnviada); // boolean
  const ganancia   = fv(f.montoProveedor) || 0;
  const rating     = fv(f.calificacion);      // 1..5 o null

  if (!acc[provId]) {
    acc[provId] = {
      proveedorId: provId,
      nombre: provNombre,
      email: provEmail,
      solicitudesRecibidas: 0,
      cotizacionesEnviadas: 0,
      trabajosGanados: 0,
      ganancias: 0,
      sumaRatings: 0,
      numRatings: 0
    };
  }
  const a = acc[provId];

  a.solicitudesRecibidas += 1;
  if (cotizo) a.cotizacionesEnviadas += 1;
  if (estado === 'ganada' || estado === 'completada') {
    a.trabajosGanados += 1;
    a.ganancias += ganancia;
  }
  if (rating != null) {
    a.sumaRatings += rating;
    a.numRatings += 1;
  }
}

// Construye un item por proveedor con su email HTML ya armado
const salida = Object.values(acc).map((a) => {
  const promedio = a.numRatings > 0 ? (a.sumaRatings / a.numRatings) : null;
  const promedioTxt = promedio != null ? promedio.toFixed(1) + ' ★' : 'Sin calificaciones';
  const gananciasTxt = '$' + a.ganancias.toFixed(2);

  const html = `
  <div style="font-family:Arial,sans-serif;max-width:560px;margin:auto;color:#1B3A6B">
    <div style="background:#1B3A6B;color:#fff;padding:20px 24px;border-radius:12px 12px 0 0">
      <h2 style="margin:0">ServiCerca · Tu resumen semanal</h2>
      <p style="margin:4px 0 0;color:#D6E6F5;font-size:13px">Semana ${semana.etiqueta}</p>
    </div>
    <div style="border:1px solid #E2E8F0;border-top:none;border-radius:0 0 12px 12px;padding:24px">
      <p style="font-size:15px">Hola <b>${a.nombre}</b>, este fue tu desempeño esta semana:</p>
      <table style="width:100%;border-collapse:collapse;font-size:14px">
        <tr><td style="padding:10px 0;border-bottom:1px solid #EEF">Solicitudes recibidas</td><td style="text-align:right;font-weight:bold">${a.solicitudesRecibidas}</td></tr>
        <tr><td style="padding:10px 0;border-bottom:1px solid #EEF">Cotizaciones enviadas</td><td style="text-align:right;font-weight:bold">${a.cotizacionesEnviadas}</td></tr>
        <tr><td style="padding:10px 0;border-bottom:1px solid #EEF">Trabajos ganados</td><td style="text-align:right;font-weight:bold;color:#16A34A">${a.trabajosGanados}</td></tr>
        <tr><td style="padding:10px 0;border-bottom:1px solid #EEF">Calificación promedio</td><td style="text-align:right;font-weight:bold;color:#D97706">${promedioTxt}</td></tr>
        <tr><td style="padding:10px 0">Ganancias</td><td style="text-align:right;font-weight:bold;color:#16A34A">${gananciasTxt}</td></tr>
      </table>
      <p style="font-size:13px;color:#4A5568;margin-top:20px">Sigue así. Mantén tu disponibilidad y perfil GPS activos para recibir más solicitudes cercanas.</p>
      <p style="font-size:12px;color:#94A3B8;margin-top:16px">ServiCerca — Tu hogar en buenas manos.</p>
    </div>
  </div>`;

  return {
    json: {
      email: a.email,
      nombre: a.nombre,
      subject: `Tu resumen semanal en ServiCerca (${a.trabajosGanados} trabajos ganados)`,
      html,
      metricas: {
        solicitudesRecibidas: a.solicitudesRecibidas,
        cotizacionesEnviadas: a.cotizacionesEnviadas,
        trabajosGanados: a.trabajosGanados,
        calificacionPromedio: promedio,
        ganancias: a.ganancias
      }
    }
  };
});

// Evita enviar correos vacíos: solo proveedores con email y actividad
return salida.filter(s => s.json.email);
